/*
 * GPIO LED Control using WiringPi
 * Compile: gcc -o led_control led_control.c -lwiringPi
 * Run: sudo ./led_control
 */

#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>
#include <unistd.h>

// Define LED pin using WiringPi pin numbering (physical pin 11 = wPi pin 0)
#define LED_PIN 0

void blink_led(int times, int delay_ms) {
    /*
     * Blink LED specified number of times
     * 
     * Args:
     *     times: Number of times to blink
     *     delay_ms: Delay in milliseconds between on/off states
     */
    for (int i = 0; i < times; i++) {
        // Turn LED ON (digitalWrite HIGH)
        digitalWrite(LED_PIN, HIGH);
        printf("LED ON\n");
        delay(delay_ms);

        // Turn LED OFF (digitalWrite LOW)
        digitalWrite(LED_PIN, LOW);
        printf("LED OFF\n");
        delay(delay_ms);
    }
}

int main(void) {
    // Initialize WiringPi library
    // Returns -1 if initialization fails
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "Error: Failed to initialize WiringPi\n");
        return 1;
    }

    printf("WiringPi initialized successfully\n");
    printf("Controlling LED on WiringPi pin %d (Physical pin 11, BCM GPIO.17)\n", LED_PIN);

    // Set LED pin to OUTPUT mode
    pinMode(LED_PIN, OUTPUT);

    printf("Blinking LED 5 times with 500ms delay...\n");

    // Blink LED 5 times with 500ms delay
    blink_led(5, 500);

    // Ensure LED is OFF at the end
    digitalWrite(LED_PIN, LOW);

    printf("LED control complete\n");

    return 0;
}
